from langgraph.checkpoint.sqlite import SqliteSaver
from vex import Policy

memory = SqliteSaver.from_conn_string(":memory:")

@vex.Policy(
    name="legal_human_review",
    rules=[
        "BLOCK_IF_NO_SIGNATURE: 'attorney_signature' not in state",
        "PAUSE_ON_HIGH_RISK: state.confidence < 0.9"
    ]
)
def attorney_breakpoint(state):
    if not state.get('attorney_signature'):
        raise vex.HumanInterventionRequired(
            "Attorney review required before proceeding"
        )
    return state

# Add as conditional edge
def should_review(state):
    return "attorney_breakpoint" if state['risk_score'] > 0.7 else "file_motion"

workflow.add_conditional_edges("analyze", should_review)
